        AND d.code IN

            #{accessDepartmentCode}



        AND 1 = 0


AND (
    o.security_level = 'GENERAL'
    OR #{allConfidential} = TRUE
    OR EXISTS (
        SELECT 1
        FROM opportunity_view_permissions ovp
        WHERE ovp.opportunity_id = o.opportunity_id
          AND ovp.user_id = #{userId}
    )
)

sql.if:
AND EXISTS (
    SELECT 1
    FROM opportunity_progress op_period
    WHERE op_period.opportunity_id = o.opportunity_id
      AND op_period.progress_date >= #{periodStartDate}
      AND op_period.progress_date < #{periodEndDate}
)
